using ArchStudy.Mvc.Services;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.Mvc.Controllers;

public static class AccountsController
{
    public static void MapEndpoints(IEndpointRouteBuilder routes)
    {
        var group = routes.MapGroup("/mvc").WithTags("MVC");

        group.MapPost("/accounts", CreateAccount);
        group.MapGet("/accounts/{id:guid}", GetAccount);
        group.MapGet("/accounts/{id:guid}/transactions", GetStatement);
        group.MapPost("/accounts/{id:guid}/deposits", Deposit);
        group.MapPost("/accounts/{id:guid}/withdrawals", Withdraw);
        group.MapPost("/transfers", Transfer);
    }

    private static async Task<IResult> CreateAccount(CreateAccountRequest req, IAccountService svc, CancellationToken ct)
    {
        var account = await svc.CreateAsync(req.Owner, ct);
        return Results.Created($"/mvc/accounts/{account.Id}", account);
    }

    private static async Task<IResult> GetAccount(Guid id, IAccountService svc, CancellationToken ct)
    {
        var account = await svc.GetAsync(id, ct);
        return account is null ? Results.NotFound() : Results.Ok(account);
    }

    private static async Task<IResult> GetStatement(Guid id, IAccountService svc, CancellationToken ct) =>
        Results.Ok(await svc.GetStatementAsync(id, ct));

    private static async Task<IResult> Deposit(Guid id, DepositRequest req, IAccountService svc, CancellationToken ct) =>
        Results.Ok(await svc.DepositAsync(id, req.Amount, ct));

    private static async Task<IResult> Withdraw(Guid id, WithdrawalRequest req, IAccountService svc, CancellationToken ct) =>
        Results.Ok(await svc.WithdrawAsync(id, req.Amount, ct));

    private static async Task<IResult> Transfer(TransferRequest req, ITransferService svc, CancellationToken ct)
    {
        await svc.TransferAsync(req.FromAccountId, req.ToAccountId, req.Amount, ct);
        return Results.NoContent();
    }
}

using ArchStudy.Mvc.Controllers;
using ArchStudy.Mvc.Persistence;
using ArchStudy.Mvc.Repositories;
using ArchStudy.Mvc.Services;
using Microsoft.AspNetCore.Routing;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.DependencyInjection;

namespace ArchStudy.Mvc;

public static class MvcModule
{
    public static IServiceCollection AddMvcModule(this IServiceCollection services)
    {
        services.AddDbContext<MvcDbContext>(o => o.UseSqlite("Data Source=archstudy-mvc.db"));
        services.AddScoped<IAccountRepository, AccountRepository>();
        services.AddScoped<ITransactionRepository, TransactionRepository>();
        services.AddScoped<IAccountService, AccountService>();
        services.AddScoped<ITransferService, TransferService>();
        return services;
    }

    public static IEndpointRouteBuilder MapMvcModule(this IEndpointRouteBuilder routes)
    {
        AccountsController.MapEndpoints(routes);
        return routes;
    }

    public static async Task EnsureDatabaseCreatedAsync(IServiceProvider services)
    {
        var db = services.GetRequiredService<MvcDbContext>();
        await db.Database.EnsureCreatedAsync();
    }
}

using ArchStudy.Shared.Dtos;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Mvc.Persistence;

public class AccountEntity
{
    public Guid Id { get; set; }
    public string Owner { get; set; } = string.Empty;
    public decimal Balance { get; set; }
    public DateTime CreatedAt { get; set; }
}

public class TransactionEntity
{
    public Guid Id { get; set; }
    public Guid AccountId { get; set; }
    public TransactionType Type { get; set; }
    public decimal Amount { get; set; }
    public DateTime Timestamp { get; set; }
    public Guid? RelatedAccountId { get; set; }
}

public class MvcDbContext(DbContextOptions<MvcDbContext> options) : DbContext(options)
{
    public DbSet<AccountEntity> Accounts => Set<AccountEntity>();
    public DbSet<TransactionEntity> Transactions => Set<TransactionEntity>();
}

using ArchStudy.Mvc.Persistence;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Mvc.Repositories;

public interface IAccountRepository
{
    Task<AccountEntity?> GetByIdAsync(Guid id, CancellationToken ct);
    Task AddAsync(AccountEntity account, CancellationToken ct);
    Task SaveChangesAsync(CancellationToken ct);
}

public class AccountRepository(MvcDbContext db) : IAccountRepository
{
    public Task<AccountEntity?> GetByIdAsync(Guid id, CancellationToken ct) =>
        db.Accounts.FirstOrDefaultAsync(a => a.Id == id, ct);

    public async Task AddAsync(AccountEntity account, CancellationToken ct) =>
        await db.Accounts.AddAsync(account, ct);

    public Task SaveChangesAsync(CancellationToken ct) => db.SaveChangesAsync(ct);
}

using ArchStudy.Mvc.Persistence;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Mvc.Repositories;

public interface ITransactionRepository
{
    Task<IReadOnlyList<TransactionEntity>> ListByAccountAsync(Guid accountId, CancellationToken ct);
    Task AddAsync(TransactionEntity transaction, CancellationToken ct);
}

public class TransactionRepository(MvcDbContext db) : ITransactionRepository
{
    public async Task<IReadOnlyList<TransactionEntity>> ListByAccountAsync(Guid accountId, CancellationToken ct) =>
        await db.Transactions
            .Where(t => t.AccountId == accountId)
            .OrderByDescending(t => t.Timestamp)
            .ToListAsync(ct);

    public async Task AddAsync(TransactionEntity transaction, CancellationToken ct) =>
        await db.Transactions.AddAsync(transaction, ct);
}

using ArchStudy.Mvc.Persistence;
using ArchStudy.Mvc.Repositories;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.Mvc.Services;

public interface IAccountService
{
    Task<AccountResponse> CreateAsync(string owner, CancellationToken ct);
    Task<AccountResponse?> GetAsync(Guid id, CancellationToken ct);
    Task<IReadOnlyList<TransactionResponse>> GetStatementAsync(Guid id, CancellationToken ct);
    Task<AccountResponse> DepositAsync(Guid id, decimal amount, CancellationToken ct);
    Task<AccountResponse> WithdrawAsync(Guid id, decimal amount, CancellationToken ct);
}

public class AccountService(
    IAccountRepository accounts,
    ITransactionRepository transactions) : IAccountService
{
    public async Task<AccountResponse> CreateAsync(string owner, CancellationToken ct)
    {
        if (string.IsNullOrWhiteSpace(owner))
            throw new ArgumentException("Owner is required", nameof(owner));

        var entity = new AccountEntity
        {
            Id = Guid.NewGuid(),
            Owner = owner,
            Balance = 0m,
            CreatedAt = DateTime.UtcNow,
        };
        await accounts.AddAsync(entity, ct);
        await accounts.SaveChangesAsync(ct);
        return ToResponse(entity);
    }

    public async Task<AccountResponse?> GetAsync(Guid id, CancellationToken ct)
    {
        var entity = await accounts.GetByIdAsync(id, ct);
        return entity is null ? null : ToResponse(entity);
    }

    public async Task<IReadOnlyList<TransactionResponse>> GetStatementAsync(Guid id, CancellationToken ct)
    {
        var list = await transactions.ListByAccountAsync(id, ct);
        return list.Select(t => new TransactionResponse(
            t.Id, t.AccountId, t.Type, t.Amount, t.Timestamp, t.RelatedAccountId)).ToList();
    }

    public async Task<AccountResponse> DepositAsync(Guid id, decimal amount, CancellationToken ct)
    {
        if (amount <= 0) throw new ArgumentException("Amount must be positive", nameof(amount));
        var entity = await accounts.GetByIdAsync(id, ct) ?? throw new KeyNotFoundException("Account not found");

        entity.Balance += amount;
        await transactions.AddAsync(new TransactionEntity
        {
            Id = Guid.NewGuid(),
            AccountId = entity.Id,
            Type = TransactionType.Deposit,
            Amount = amount,
            Timestamp = DateTime.UtcNow,
        }, ct);
        await accounts.SaveChangesAsync(ct);
        return ToResponse(entity);
    }

    public async Task<AccountResponse> WithdrawAsync(Guid id, decimal amount, CancellationToken ct)
    {
        if (amount <= 0) throw new ArgumentException("Amount must be positive", nameof(amount));
        var entity = await accounts.GetByIdAsync(id, ct) ?? throw new KeyNotFoundException("Account not found");
        if (entity.Balance < amount) throw new InvalidOperationException("Insufficient funds");

        entity.Balance -= amount;
        await transactions.AddAsync(new TransactionEntity
        {
            Id = Guid.NewGuid(),
            AccountId = entity.Id,
            Type = TransactionType.Withdrawal,
            Amount = amount,
            Timestamp = DateTime.UtcNow,
        }, ct);
        await accounts.SaveChangesAsync(ct);
        return ToResponse(entity);
    }

    private static AccountResponse ToResponse(AccountEntity a) =>
        new(a.Id, a.Owner, a.Balance, a.CreatedAt);
}

using ArchStudy.Mvc.Persistence;
using ArchStudy.Mvc.Repositories;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.Mvc.Services;

public interface ITransferService
{
    Task TransferAsync(Guid fromId, Guid toId, decimal amount, CancellationToken ct);
}

public class TransferService(
    IAccountRepository accounts,
    ITransactionRepository transactions) : ITransferService
{
    public async Task TransferAsync(Guid fromId, Guid toId, decimal amount, CancellationToken ct)
    {
        if (amount <= 0) throw new ArgumentException("Amount must be positive", nameof(amount));
        if (fromId == toId) throw new ArgumentException("Accounts must differ");

        var from = await accounts.GetByIdAsync(fromId, ct) ?? throw new KeyNotFoundException("Source account not found");
        var to = await accounts.GetByIdAsync(toId, ct) ?? throw new KeyNotFoundException("Destination account not found");
        if (from.Balance < amount) throw new InvalidOperationException("Insufficient funds");

        from.Balance -= amount;
        to.Balance += amount;

        var now = DateTime.UtcNow;
        await transactions.AddAsync(new TransactionEntity
        {
            Id = Guid.NewGuid(),
            AccountId = from.Id,
            Type = TransactionType.TransferOut,
            Amount = amount,
            Timestamp = now,
            RelatedAccountId = to.Id,
        }, ct);
        await transactions.AddAsync(new TransactionEntity
        {
            Id = Guid.NewGuid(),
            AccountId = to.Id,
            Type = TransactionType.TransferIn,
            Amount = amount,
            Timestamp = now,
            RelatedAccountId = from.Id,
        }, ct);

        await accounts.SaveChangesAsync(ct);
    }
}
